```python
import re

def pruefe_passwort_staerke(passwort):
    # Reguläre Ausdrücke für die Überprüfung der Passwortstärke
    min_8_ziffern = re.compile(r".{8,}")
    min_1_buchstabe = re.compile(r"[a-zA-Z]")
    min_1_zahl = re.compile(r"\d")
    min_1_sonderzeichen = re.compile(r"[!@#$%^&*()_+=-{};:'<>,./?]")
    min_1_großbuchstabe = re.compile(r"[A-Z]")
    min_1_kleinbuchstabe = re.compile(r"[a-z]")

    # Überprüfung der Passwortstärke
    if min_8_ziffern.match(passwort):
        print("Das Passwort ist mindestens 8 Zeichen lang.")
    else:
        print("Das Passwort ist nicht mindestens 8 Zeichen lang.")

    if min_1_buchstabe.search(passwort):
        print("Das Passwort enthält mindestens einen Buchstaben.")
    else:
        print("Das Passwort enthält keinen Buchstaben.")

    if min_1_zahl.search(passwort):
        print("Das Passwort enthält mindestens eine Zahl.")
    else:
        print("Das Passwort enthält keine Zahl.")

    if min_1_sonderzeichen.search(passwort):
        print("Das Passwort enthält mindestens ein Sonderzeichen.")
    else:
        print("Das Passwort enthält kein Sonderzeichen.")

    if min_1_großbuchstabe.search(passwort):
        print("Das Passwort enthält mindestens einen Großbuchstaben.")
    else:
        print("Das Passwort enthält keinen Großbuchstaben.")

    if min_1_kleinbuchstabe.search(passwort):
        print("Das Passwort enthält mindestens einen Kleinbuchstaben.")
    else:
        print("Das Passwort enthält keinen Kleinbuchstaben.")

# Beispielaufruf
pruefe_passwort_staerke("MeinPasswort123!")
```
